import{_ as t}from"./chunks/comparison.D69ELQo5.js";import{_ as a,o as s,c as r,ao as i}from"./chunks/framework.yEt8qnMJ.js";const u=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md","lastUpdated":null}'),n={name:"benchmarks.md"};function d(o,e,l,h,g,p){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="Benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#Benchmarks" aria-label="Permalink to &quot;Benchmarks {#Benchmarks}&quot;">​</a></h1><p>Dewdrop is benchmarked against the established simulators (Brian2 and brian2cuda, BrainPy, NEST and NEST GPU, and GeNN) on the <strong>same</strong> network: a recurrent excitatory/inhibitory <a href="/Dewdrop.jl/dev/guide/models#AdEx"><code>AdEx</code></a> net with a fixed in-degree and current-based exponential synapses, the regime where the sparse synaptic scatter dominates. Every simulator builds an <em>identical</em> connectome (a language-agnostic splitmix64 sample, verified edge-for-edge) and is checked to produce statistically matching firing rates and CV-ISI before any timing is compared, so the numbers are apples-to-apples.</p><p><img src="'+t+`" alt=""></p><p>The panels show wall-clock time and peak memory as the network grows from 2,000 to 512,000 neurons, on the CPU (top) and GPU (bottom). Dewdrop&#39;s three CPU execution backends (<a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Serial"><code>Serial</code></a>/<a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a>/<a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Turbo"><code>Turbo</code></a>) and its GPU <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a> megakernel are each plotted separately; see <a href="./guide/backends">choosing a backend</a>.</p><h2 id="Headline-numbers" tabindex="-1">Headline numbers <a class="header-anchor" href="#Headline-numbers" aria-label="Permalink to &quot;Headline numbers {#Headline-numbers}&quot;">​</a></h2><p>Wall-clock time (lower is better) and peak memory at a mid-size and a large network. The relative ordering is the point; absolute values depend on the machine.</p><p><strong>CPU</strong></p><table tabindex="0"><thead><tr><th style="text-align:right;">Simulator (CPU)</th><th style="text-align:right;">time @ N=16k</th><th style="text-align:right;">time @ N=512k</th><th style="text-align:right;">memory @ N=512k</th></tr></thead><tbody><tr><td style="text-align:right;">Dewdrop <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a></td><td style="text-align:right;">0.36 s</td><td style="text-align:right;"><strong>7.5 s</strong></td><td style="text-align:right;">3.8 GB</td></tr><tr><td style="text-align:right;">Dewdrop <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Turbo"><code>Turbo</code></a></td><td style="text-align:right;">0.54 s</td><td style="text-align:right;">20.8 s</td><td style="text-align:right;">3.9 GB</td></tr><tr><td style="text-align:right;">Dewdrop <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Serial"><code>Serial</code></a></td><td style="text-align:right;">1.97 s</td><td style="text-align:right;">56.3 s</td><td style="text-align:right;">3.8 GB</td></tr><tr><td style="text-align:right;">Brian2 (C++ standalone)</td><td style="text-align:right;">0.38 s</td><td style="text-align:right;">25.6 s</td><td style="text-align:right;">3.3 GB</td></tr><tr><td style="text-align:right;">BrainPy (JAX)</td><td style="text-align:right;">1.33 s</td><td style="text-align:right;">25.4 s</td><td style="text-align:right;">4.2 GB</td></tr><tr><td style="text-align:right;">NEST</td><td style="text-align:right;">1.83 s</td><td style="text-align:right;">116.7 s</td><td style="text-align:right;">9.5 GB</td></tr></tbody></table><p><strong>GPU</strong></p><table tabindex="0"><thead><tr><th style="text-align:right;">Simulator (GPU)</th><th style="text-align:right;">time @ N=16k</th><th style="text-align:right;">time @ N=512k</th><th style="text-align:right;">memory @ N=512k</th></tr></thead><tbody><tr><td style="text-align:right;">Dewdrop <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a></td><td style="text-align:right;">0.069 s</td><td style="text-align:right;"><strong>0.24 s</strong></td><td style="text-align:right;">1.3 GB</td></tr><tr><td style="text-align:right;">GeNN (CUDA)</td><td style="text-align:right;">0.067 s</td><td style="text-align:right;">1.94 s</td><td style="text-align:right;">3.6 GB</td></tr><tr><td style="text-align:right;">brian2cuda</td><td style="text-align:right;">0.145 s</td><td style="text-align:right;">0.53 s</td><td style="text-align:right;">2.7 GB</td></tr><tr><td style="text-align:right;">NEST GPU</td><td style="text-align:right;">0.32 s</td><td style="text-align:right;">1.40 s</td><td style="text-align:right;">1.7 GB</td></tr></tbody></table><h2 id="What-the-scaling-shows" tabindex="-1">What the scaling shows <a class="header-anchor" href="#What-the-scaling-shows" aria-label="Permalink to &quot;What the scaling shows {#What-the-scaling-shows}&quot;">​</a></h2><ul><li><p><strong>CPU, at scale.</strong> Dewdrop&#39;s <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a> backend is the fastest CPU simulator measured: at N=512k it is <strong>3.4× faster than Brian2&#39;s compiled C++</strong>, 3.4× faster than BrainPy, and 15.6× faster than NEST, with no code-generation or compile step.</p></li><li><p><strong>CPU, small networks.</strong> <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a> (0.36 s) sits within a few percent of Brian2&#39;s hand-tuned C++ standalone (0.38 s) at N=16k: a pure-Julia engine at near-compiled-C++ throughput.</p></li><li><p><strong>GPU, small networks.</strong> Dewdrop&#39;s GPU megakernel ties GeNN&#39;s generated CUDA (0.069 vs 0.067 s) and is roughly 2× faster than brian2cuda and 4-5× faster than NEST GPU: the launch-bound regime where the fused step removes per-phase kernel launches.</p></li><li><p><strong>GPU, at scale.</strong> Dewdrop is fastest by a clear margin: at N=512k it is 2.2× faster than brian2cuda, 5.9× faster than NEST GPU, and 8× faster than GeNN, whose generated kernels degrade superlinearly there. It is also the leanest on the device at scale (1.3 GB).</p></li><li><p><strong>Memory.</strong> On the CPU, Dewdrop is mid-pack (Brian2&#39;s standalone is the leanest, NEST by far the heaviest); on the GPU at scale, Dewdrop uses the least memory of the four.</p></li></ul><p>The combination (competitive at small sizes on both devices and the fastest at scale) comes from the struct-of-arrays state, the fused single-pass step that pipelines on one device stream, and the compacted spike scatter that keeps the GPU off the memory-bandwidth wall (see <a href="./guide/gpu">running on the GPU</a>).</p><h2 id="Methodology" tabindex="-1">Methodology <a class="header-anchor" href="#Methodology" aria-label="Permalink to &quot;Methodology {#Methodology}&quot;">​</a></h2><p>The shared problem (one <code>spec.toml</code> consumed by every simulator):</p><ul><li><p><strong>Network.</strong> Recurrent E/I <a href="/Dewdrop.jl/dev/guide/models#AdEx"><code>AdEx</code></a>, 80% excitatory, fixed in-degree K=100, CUBA exponential synapses with a constant external drive: the sparse-scatter-dominated regime.</p></li><li><p><strong>Connectome.</strong> Generated by a language-agnostic splitmix64 algorithm so every simulator builds the identical graph; the comparison harness verifies the edge count matches across all simulators.</p></li><li><p><strong>Run.</strong> <code>dt = 0.1</code> ms, 500 ms for the throughput scan (one network size per octave from 2k to 512k), 1000 ms for the correctness run that checks firing rate and CV-ISI agree.</p></li><li><p><strong>Measured.</strong> End-to-end wall time of the integration and peak resident memory, per simulator, per size, on CPU and (where supported) GPU. Absolute timings are machine-dependent; the scaling slopes and the relative ordering are the reproducible result.</p></li></ul><p>Each simulator is implemented as its own self-contained runner under <code>test/simulator_comparisons/&lt;sim&gt;/</code> (Dewdrop in Julia, Brian2/BrainPy/NEST/GeNN in Python), writing standard <code>out/performance.csv</code> files; <code>compare_simulators.jl</code> discovers them, verifies they ran the same simulation, and produces the figure above. Adding a simulator is dropping in a directory.</p><h2 id="Reproducing" tabindex="-1">Reproducing <a class="header-anchor" href="#Reproducing" aria-label="Permalink to &quot;Reproducing {#Reproducing}&quot;">​</a></h2><p>From the package&#39;s <code>test/simulator_comparisons/</code> directory, run each simulator&#39;s runner and then the aggregator (see that directory&#39;s <code>README.md</code> and <code>run_all.sh</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dewdrop/run.jl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Dewdrop, all sizes, CPU + GPU</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> brian/run.py</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # each other simulator in its own environment</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compare_simulators.jl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # verify + plot to out/comparison.pdf</span></span></code></pre></div>`,20)])])}const y=a(n,[["render",d]]);export{u as __pageData,y as default};
